@* Displays a single task as a card with move buttons *@

<div class="card mb-2">
    <div class="card-body p-2">
        <h6 class="card-title mb-1">@Task.Title</h6>
        <p class="card-text mb-1">
            <small class="text-muted">@Task.Assignee</small>
        </p>
        <span class="badge bg-@PriorityClass me-1">@Task.Priority</span>
        <small class="text-muted">@Task.DueDate.ToString("MMM dd")</small>
        <div class="mt-2">
            @if (ShowMoveLeft)
            {
                <button class="btn btn-outline-secondary btn-sm me-1"
                        @onclick="OnMoveLeft"
                        disabled="@IsMoving">
                    &larr; Move Left
                </button>
            }
            @if (ShowMoveRight)
            {
                <button class="btn btn-outline-secondary btn-sm"
                        @onclick="OnMoveRight"
                        disabled="@IsMoving">
                    Move Right &rarr;
                </button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveLeftClicked { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveRightClicked { get; set; }
    [Parameter] public bool IsMoving { get; set; }

    private string PriorityClass => Task.Priority switch
    {
        "High" => "danger",
        "Medium" => "warning",
        _ => "success"
    };

    private async System.Threading.Tasks.Task OnMoveLeft() => await OnMoveLeftClicked.InvokeAsync(Task);
    private async System.Threading.Tasks.Task OnMoveRight() => await OnMoveRightClicked.InvokeAsync(Task);
}

