@* Inline form to create a new task within a column *@

<div class="card mb-2 border-primary">
    <div class="card-body p-2">
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Title"
                   @bind="Title" />
        </div>
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Assignee"
                   @bind="Assignee" />
        </div>
        <div class="mb-2">
            <select class="form-select form-select-sm" @bind="Priority">
                <option value="High">High</option>
                <option value="Medium">Medium</option>
                <option value="Low">Low</option>
            </select>
        </div>
        <div class="mb-2">
            <input type="date" class="form-control form-control-sm" @bind="DueDate" />
        </div>
        <div>
            <button class="btn btn-primary btn-sm me-1" @onclick="Save" disabled="@IsSaving">
                Save
            </button>
            <button class="btn btn-secondary btn-sm" @onclick="Cancel" disabled="@IsSaving">
                Cancel
            </button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public EventCallback<AddTaskRequest> OnSave { get; set; }
    [Parameter, EditorRequired] public EventCallback OnCancel { get; set; }

    private string Title { get; set; } = string.Empty;
    private string Assignee { get; set; } = string.Empty;
    private string Priority { get; set; } = "Medium";
    private DateTime DueDate { get; set; } = DateTime.Today.AddDays(7);
    private bool IsSaving { get; set; }

    private async Task Save()
    {
        if (string.IsNullOrWhiteSpace(Title)) return;

        IsSaving = true;
        await OnSave.InvokeAsync(new AddTaskRequest(Title.Trim(), Assignee.Trim(), Priority, DueDate));
        IsSaving = false;
    }

    private async Task Cancel() => await OnCancel.InvokeAsync();

    public record AddTaskRequest(string Title, string Assignee, string Priority, DateTime DueDate);
}

@using static AddTaskForm

@* A single Kanban column with header, task cards, and add-task form *@

<div class="col">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>@ColumnName</strong>
            <span class="badge bg-secondary">@Tasks.Count</span>
        </div>
        <div class="card-body p-2" style="min-height: 200px; overflow-y: auto;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          ShowMoveLeft="ShowMoveLeft"
                          ShowMoveRight="ShowMoveRight"
                          OnMoveLeftClicked="OnMoveLeft"
                          OnMoveRightClicked="OnMoveRight"
                          IsMoving="IsMoving" />
            }

            @if (ShowAddForm)
            {
                <AddTaskForm OnSave="HandleSave" OnCancel="HandleCancel" />
            }
        </div>
        <div class="card-footer p-2">
            <button class="btn btn-outline-primary btn-sm w-100" @onclick="ToggleAddForm"
                    disabled="@ShowAddForm">
                + Add Task
            </button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = string.Empty;
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveLeft { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveRight { get; set; }
    [Parameter] public EventCallback<AddTaskRequest> OnAddTask { get; set; }
    [Parameter] public bool IsMoving { get; set; }

    private bool ShowAddForm { get; set; }

    private void ToggleAddForm() => ShowAddForm = true;

    private async Task HandleSave(AddTaskRequest request)
    {
        await OnAddTask.InvokeAsync(request);
        ShowAddForm = false;
    }

    private void HandleCancel() => ShowAddForm = false;
}

