@page "/board"
@rendermode InteractiveServer
@using sv_93ddd628403d4f8fb8535c511b44da81.Components.Board
@using static AddTaskForm
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Project Board</h3>

@if (_loading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (_error is not null)
{
    <div class="alert alert-danger">
        <strong>Error loading tasks:</strong> @_error
        <button class="btn btn-outline-danger btn-sm ms-2" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStatsBar Total="@_allTasks.Count"
                   TodoCount="@TodoTasks.Count"
                   InProgressCount="@InProgressTasks.Count"
                   DoneCount="@DoneTasks.Count"
                   OverdueCount="@OverdueCount" />

    <BoardSearchBar @bind-SearchTerm="_searchTerm" />

    <div class="row g-3">
        <KanbanColumn ColumnName="To Do"
                      Tasks="FilteredTodo"
                      ShowMoveLeft="false"
                      ShowMoveRight="true"
                      OnMoveRight="MoveRight"
                      OnAddTask="request => AddTask(request, \"To Do\")"
                      IsMoving="_isMoving" />

        <KanbanColumn ColumnName="In Progress"
                      Tasks="FilteredInProgress"
                      ShowMoveLeft="true"
                      ShowMoveRight="true"
                      OnMoveLeft="MoveLeft"
                      OnMoveRight="MoveRight"
                      OnAddTask="request => AddTask(request, \"In Progress\")"
                      IsMoving="_isMoving" />

        <KanbanColumn ColumnName="Done"
                      Tasks="FilteredDone"
                      ShowMoveLeft="true"
                      ShowMoveRight="false"
                      OnMoveLeft="MoveLeft"
                      OnAddTask="request => AddTask(request, \"Done\")"
                      IsMoving="_isMoving" />
    </div>
}

@code {
    private List<TaskItem> _allTasks = new();
    private string _searchTerm = string.Empty;
    private bool _loading = true;
    private string? _error;
    private bool _isMoving;

    private static readonly string[] StatusOrder = ["To Do", "In Progress", "Done"];

    private List<TaskItem> TodoTasks => _allTasks.Where(t => t.Status == "To Do").ToList();
    private List<TaskItem> InProgressTasks => _allTasks.Where(t => t.Status == "In Progress").ToList();
    private List<TaskItem> DoneTasks => _allTasks.Where(t => t.Status == "Done").ToList();

    private List<TaskItem> FilteredTodo => ApplySearch(TodoTasks);
    private List<TaskItem> FilteredInProgress => ApplySearch(InProgressTasks);
    private List<TaskItem> FilteredDone => ApplySearch(DoneTasks);

    private int OverdueCount => _allTasks.Count(t => t.DueDate < DateTime.Today);

    private List<TaskItem> ApplySearch(List<TaskItem> tasks)
    {
        if (string.IsNullOrWhiteSpace(_searchTerm))
            return tasks;
        return tasks.Where(t => t.Title.Contains(_searchTerm, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        _loading = true;
        _error = null;
        try
        {
            _allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task MoveLeft(TaskItem task)
    {
        var currentIndex = Array.IndexOf(StatusOrder, task.Status);
        if (currentIndex <= 0) return;
        await MoveTask(task, StatusOrder[currentIndex - 1]);
    }

    private async Task MoveRight(TaskItem task)
    {
        var currentIndex = Array.IndexOf(StatusOrder, task.Status);
        if (currentIndex < 0 || currentIndex >= StatusOrder.Length - 1) return;
        await MoveTask(task, StatusOrder[currentIndex + 1]);
    }

    private async Task MoveTask(TaskItem task, string newStatus)
    {
        _isMoving = true;
        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            var index = _allTasks.FindIndex(t => t.Id == task.Id);
            if (index >= 0)
                _allTasks[index] = task with { Status = newStatus };
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _isMoving = false;
        }
    }

    private async Task AddTask(AddTaskRequest request, string status)
    {
        try
        {
            var newTask = await TaskService.CreateTaskAsync(request.Title, request.Assignee, request.Priority, request.DueDate);
            _allTasks.Add(newTask with { Status = status });
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
    }
}

