1. @page "/board"
2. @rendermode InteractiveServer
3. @using static sv_93ddd628403d4f8fb8535c511b44da81.Components.Board.AddTaskForm
4. @inject ITaskService TaskService
5. 
6. <PageTitle>Kanban Board</PageTitle>
7. 
8. <h3 class="mb-3">Project Board</h3>
9. 
10. @if (_loading)
11. {
12.     <div class="d-flex justify-content-center my-5">
13.         <div class="spinner-border" role="status">
14.             <span class="visually-hidden">Loading...</span>
15.         </div>
16.     </div>
17. }
18. else if (_error is not null)
19. {
20.     <div class="alert alert-danger">
21.         <strong>Error loading tasks:</strong> @_error
22.         <button class="btn btn-outline-danger btn-sm ms-2" @onclick="LoadTasks">Retry</button>
23.     </div>
24. }
25. else
26. {
27.     <BoardStatsBar Total="@_allTasks.Count"
28.                    TodoCount="@TodoTasks.Count"
29.                    InProgressCount="@InProgressTasks.Count"
30.                    DoneCount="@DoneTasks.Count"
31.                    OverdueCount="@OverdueCount" />
32. 
33.     <BoardSearchBar @bind-SearchTerm="_searchTerm" />
34. 
35.     <div class="row g-3">
36.         <KanbanColumn ColumnName="To Do"
37.                       Tasks="FilteredTodo"
38.                       ShowMoveLeft="false"
39.                       ShowMoveRight="true"
40.                       OnMoveRight="MoveRight"
41.                       OnAddTask="request => AddTask(request, StatusTodo)"
42.                       IsMoving="_isMoving" />
43. 
44.         <KanbanColumn ColumnName="In Progress"
45.                       Tasks="FilteredInProgress"
46.                       ShowMoveLeft="true"
47.                       ShowMoveRight="true"
48.                       OnMoveLeft="MoveLeft"
49.                       OnMoveRight="MoveRight"
50.                       OnAddTask="request => AddTask(request, StatusInProgress)"
51.                       IsMoving="_isMoving" />
52. 
53.         <KanbanColumn ColumnName="Done"
54.                       Tasks="FilteredDone"
55.                       ShowMoveLeft="true"
56.                       ShowMoveRight="false"
57.                       OnMoveLeft="MoveLeft"
58.                       OnAddTask="request => AddTask(request, StatusDone)"
59.                       IsMoving="_isMoving" />
60.     </div>
61. }
62. 
63. @code {
64.     private List<TaskItem> _allTasks = new();
65.     private string _searchTerm = string.Empty;
66.     private bool _loading = true;
67.     private string? _error;
68.     private bool _isMoving;
69. 
70.     private const string StatusTodo = "To Do";
71.     private const string StatusInProgress = "In Progress";
72.     private const string StatusDone = "Done";
73.     private static readonly string[] StatusOrder = [StatusTodo, StatusInProgress, StatusDone];
74. 
75.     private List<TaskItem> TodoTasks => _allTasks.Where(t => t.Status == StatusTodo).ToList();
76.     private List<TaskItem> InProgressTasks => _allTasks.Where(t => t.Status == StatusInProgress).ToList();
77.     private List<TaskItem> DoneTasks => _allTasks.Where(t => t.Status == StatusDone).ToList();
78. 
79.     private List<TaskItem> FilteredTodo => ApplySearch(TodoTasks);
80.     private List<TaskItem> FilteredInProgress => ApplySearch(InProgressTasks);
81.     private List<TaskItem> FilteredDone => ApplySearch(DoneTasks);
82. 
83.     private int OverdueCount => _allTasks.Count(t => t.DueDate < DateTime.Today);
84. 
85.     private List<TaskItem> ApplySearch(List<TaskItem> tasks)
86.     {
87.         if (string.IsNullOrWhiteSpace(_searchTerm))
88.             return tasks;
89.         return tasks.Where(t => t.Title.Contains(_searchTerm, StringComparison.OrdinalIgnoreCase)).ToList();
90.     }
91. 
92.     protected override async Task OnInitializedAsync()
93.     {
94.         await LoadTasks();
95.     }
96. 
97.     private async Task LoadTasks()
98.     {
99.         _loading = true;
100.         _error = null;
101.         try
102.         {
103.             _allTasks = await TaskService.GetAllTasksAsync();
104.         }
105.         catch (Exception ex)
106.         {
107.             _error = ex.Message;
108.         }
109.         finally
110.         {
111.             _loading = false;
112.         }
113.     }
114. 
115.     private async Task MoveLeft(TaskItem task)
116.     {
117.         var currentIndex = Array.IndexOf(StatusOrder, task.Status);
118.         if (currentIndex <= 0) return;
119.         await MoveTask(task, StatusOrder[currentIndex - 1]);
120.     }
121. 
122.     private async Task MoveRight(TaskItem task)
123.     {
124.         var currentIndex = Array.IndexOf(StatusOrder, task.Status);
125.         if (currentIndex < 0 || currentIndex >= StatusOrder.Length - 1) return;
126.         await MoveTask(task, StatusOrder[currentIndex + 1]);
127.     }
128. 
129.     private async Task MoveTask(TaskItem task, string newStatus)
130.     {
131.         _isMoving = true;
132.         try
133.         {
134.             await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
135.             var index = _allTasks.FindIndex(t => t.Id == task.Id);
136.             if (index >= 0)
137.                 _allTasks[index] = task with { Status = newStatus };
138.         }
139.         catch (Exception ex)
140.         {
141.             _error = ex.Message;
142.         }
143.         finally
144.         {
145.             _isMoving = false;
146.         }
147.     }
148. 
149.     private async Task AddTask(AddTaskRequest request, string status)
150.     {
151.         try
152.         {
153.             var newTask = await TaskService.CreateTaskAsync(request.Title, request.Assignee, request.Priority, request.DueDate);
154.             _allTasks.Add(newTask with { Status = status });
155.         }
156.         catch (Exception ex)
157.         {
158.             _error = ex.Message;
159.         }
160.     }
161. }
162.

