     private string? _error;
     private bool _isMoving;

     private const string StatusTodo = "To Do";
     private const string StatusInProgress = "In Progress";
     private const string StatusDone = "Done";
     private static readonly string[] StatusOrder = [StatusTodo, StatusInProgress, StatusDone];

     private List<TaskItem> TodoTasks => _allTasks.Where(t => t.Status == StatusTodo).ToList();
     private List<TaskItem> InProgressTasks => _allTasks.Where(t => t.Status == StatusInProgress).ToList();
     private List<TaskItem> DoneTasks => _allTasks.Where(t => t.Status == StatusDone).ToList();

     private List<TaskItem> FilteredTodo => ApplySearch(TodoTasks);
     private List<TaskItem> FilteredInProgress => ApplySearch(InProgressTasks);
     private List<TaskItem> FilteredDone => ApplySearch(DoneTasks);

     private int OverdueCount => _allTasks.Count(t => t.DueDate < DateTime.Today);

     private List<TaskItem> ApplySearch(List<TaskItem> tasks)
     {
         if (string.IsNullOrWhiteSpace(_searchTerm))
             return tasks;
         return tasks.Where(t => t.Title.Contains(_searchTerm, StringComparison.OrdinalIgnoreCase)).ToList();
     }

     protected override async Task OnInitializedAsync()
     {
         await LoadTasks();
     }

     private async Task LoadTasks()
     {
